mapper.select:
SELECT id, user_id, character_id, title, created_at, updated_at
FROM app_conversation
WHERE id = #{conversationId}
  AND user_id = #{userId}

SELECT id
FROM app_conversation
WHERE user_id = #{userId}
  AND character_id = #{characterId}
ORDER BY id ASC

mapper.update:
UPDATE app_conversation
SET updated_at = CURRENT_TIMESTAMP
WHERE id = #{conversationId}

mapper.delete:
DELETE FROM app_conversation
WHERE id = #{conversationId}
  AND user_id = #{userId}
